#include<bits/stdc++.h>
using namespace std;
int dp[101];
int main()
{
    int n,ans=0;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        int max1=0;
        for(int i=0;i<31;i++)
        {
            if(x&(1<<i))
            {
                max1=max(max1,dp[i]);
            }
        }
        ans=max(ans,max1+1);
        for(int i=0;i<31;i++)
        {
            if(x&(1<<i))
            {
                dp[i]=max(dp[i],max1+1);
            }
        }
    }
    printf("%d",ans);
    return 0;
}
